CREATE TABLE acceptance_requirements(id TEXT PRIMARY KEY,schema_version INTEGER NOT NULL DEFAULT 1 CHECK(schema_version=1),sequence INTEGER NOT NULL CHECK(sequence >= 0),source_lineage TEXT NOT NULL DEFAULT 'native',correction_of TEXT);
CREATE TABLE artifacts(id TEXT PRIMARY KEY,owner TEXT NOT NULL,source TEXT NOT NULL, schema_version INTEGER NOT NULL DEFAULT 1);
CREATE TABLE captured_outcome_simulations(id TEXT PRIMARY KEY,label TEXT NOT NULL CHECK(label='captured_outcome_simulation'),outcome TEXT NOT NULL,exact_playback_evidence INTEGER NOT NULL DEFAULT 0 CHECK(exact_playback_evidence=0), schema_version INTEGER NOT NULL DEFAULT 1, source_lineage TEXT NOT NULL DEFAULT 'native');
CREATE TABLE compatibility_decisions(id INTEGER PRIMARY KEY,source_schema_version INTEGER NOT NULL,target_schema_version INTEGER NOT NULL,operation TEXT NOT NULL,actor TEXT NOT NULL,source TEXT NOT NULL,outcome TEXT NOT NULL,fingerprint TEXT NOT NULL UNIQUE,result TEXT NOT NULL);
CREATE TABLE discrepancies(id INTEGER PRIMARY KEY,operation TEXT NOT NULL UNIQUE,actor TEXT NOT NULL,artifact_id TEXT NOT NULL,source TEXT NOT NULL,ancestry TEXT,reason TEXT NOT NULL,status TEXT NOT NULL,operation_result_id TEXT NOT NULL,expected_hash TEXT,observed_hash TEXT,context TEXT NOT NULL, expected_identity TEXT, observed_identity TEXT, schema_version INTEGER NOT NULL DEFAULT 1, proposed_hash TEXT, observed_owner TEXT, observed_source TEXT, observed_ancestry TEXT);
CREATE TABLE events(id TEXT PRIMARY KEY,schema_version INTEGER NOT NULL CHECK(schema_version=1),source_lineage TEXT NOT NULL,correction_of TEXT,event_sequence INTEGER NOT NULL DEFAULT 0,transition TEXT NOT NULL DEFAULT '',deterministic_input TEXT NOT NULL DEFAULT '',outcome TEXT);
CREATE TABLE evidence(id TEXT PRIMARY KEY,schema_version INTEGER NOT NULL DEFAULT 1 CHECK(schema_version=1),source_lineage TEXT NOT NULL,correction_of TEXT);
CREATE TABLE findings(id TEXT PRIMARY KEY,schema_version INTEGER NOT NULL CHECK(schema_version=1),source_lineage TEXT NOT NULL,correction_of TEXT);
CREATE TABLE history(id TEXT PRIMARY KEY,schema_version INTEGER NOT NULL DEFAULT 1 CHECK(schema_version=1),source_lineage TEXT NOT NULL,correction_of TEXT);
CREATE TABLE lifecycle_evidence(id TEXT PRIMARY KEY,schema_version INTEGER NOT NULL DEFAULT 1 CHECK(schema_version=1),status TEXT NOT NULL CHECK(status IN ('created','invalidated')),actor TEXT NOT NULL,reason TEXT NOT NULL,content_version TEXT NOT NULL,operation_lineage TEXT NOT NULL,source_lineage TEXT NOT NULL DEFAULT 'native',correction_of TEXT);
CREATE TABLE lineage(operation_id TEXT PRIMARY KEY,version_id TEXT NOT NULL,parent_version_id TEXT, schema_version INTEGER NOT NULL DEFAULT 1,FOREIGN KEY(operation_id) REFERENCES operations(id),FOREIGN KEY(version_id) REFERENCES versions(id),FOREIGN KEY(parent_version_id) REFERENCES versions(id));
CREATE TABLE operations(id TEXT PRIMARY KEY,fingerprint TEXT NOT NULL,result TEXT NOT NULL,version_id TEXT,lineage TEXT,rejection_code TEXT,schema_version INTEGER NOT NULL,FOREIGN KEY(version_id) REFERENCES versions(id));
CREATE TABLE outcomes(id TEXT PRIMARY KEY,schema_version INTEGER NOT NULL DEFAULT 1 CHECK(schema_version=1),outcome TEXT NOT NULL CHECK(outcome IN ('verified','accepted_with_waivers','accepted_partial','blocked','aborted','failed')),source_lineage TEXT NOT NULL DEFAULT 'native',correction_of TEXT);
CREATE TABLE playback_results(id TEXT PRIMARY KEY,event_history_generation INTEGER NOT NULL,result TEXT NOT NULL CHECK(result IN ('exact_playback_succeeded','diverged')),divergence TEXT,exact INTEGER NOT NULL CHECK(exact IN (0,1)), schema_version INTEGER NOT NULL DEFAULT 1, source_lineage TEXT NOT NULL DEFAULT 'native');
CREATE TABLE projection_rebuild_status(projection_id TEXT PRIMARY KEY,status TEXT NOT NULL CHECK(status IN ('missing','stale','drifted','complete','failed')),authoritative INTEGER NOT NULL CHECK(authoritative IN (0,1)),failure TEXT,drift TEXT, schema_version INTEGER NOT NULL DEFAULT 1, source_lineage TEXT NOT NULL DEFAULT 'native');
CREATE TABLE projection_rebuilds(id INTEGER PRIMARY KEY,projection_id TEXT NOT NULL,event_id TEXT NOT NULL,event_sequence INTEGER NOT NULL,status TEXT NOT NULL CHECK(status IN ('complete','failed')),failure TEXT,drift TEXT, schema_version INTEGER NOT NULL DEFAULT 1, source_lineage TEXT NOT NULL DEFAULT 'native');
CREATE TABLE projections(id TEXT PRIMARY KEY,projection_schema_version INTEGER NOT NULL,event_history_generation INTEGER NOT NULL,source_generation INTEGER NOT NULL,authoritative INTEGER NOT NULL CHECK(authoritative IN (0,1)),status TEXT NOT NULL CHECK(status IN ('missing','stale','drifted','complete','failed')),payload TEXT NOT NULL DEFAULT '', schema_version INTEGER NOT NULL DEFAULT 1, source_lineage TEXT NOT NULL DEFAULT 'native');
CREATE TABLE replay_metadata(id TEXT PRIMARY KEY,schema_version INTEGER NOT NULL DEFAULT 1 CHECK(schema_version=1),source_lineage TEXT NOT NULL,correction_of TEXT);
CREATE TABLE retrospectives(id TEXT PRIMARY KEY,schema_version INTEGER NOT NULL DEFAULT 1 CHECK(schema_version=1),sequence INTEGER NOT NULL CHECK(sequence >= 0),source_lineage TEXT NOT NULL DEFAULT 'native',correction_of TEXT);
CREATE TABLE reviewer_findings(id TEXT PRIMARY KEY,schema_version INTEGER NOT NULL CHECK(schema_version=1),state TEXT NOT NULL CHECK(state IN ('open','acknowledged','fixed','waived','rejected','stale')),source_lineage TEXT NOT NULL DEFAULT 'native',correction_of TEXT);
CREATE TABLE schema_metadata(key TEXT PRIMARY KEY,value INTEGER NOT NULL);
INSERT INTO schema_metadata VALUES('schema_version',2),('migration_lineage',1);
CREATE TABLE versions(id TEXT PRIMARY KEY,artifact_id TEXT NOT NULL,hash TEXT NOT NULL,canonical TEXT NOT NULL,ancestry TEXT,operation TEXT NOT NULL UNIQUE,actor TEXT NOT NULL,source TEXT NOT NULL,observed_identity TEXT,expected_hash TEXT,schema_version INTEGER NOT NULL, source_schema_version INTEGER NOT NULL DEFAULT 1, source_lineage TEXT NOT NULL DEFAULT 'native',FOREIGN KEY(artifact_id) REFERENCES artifacts(id),FOREIGN KEY(ancestry) REFERENCES versions(id));
CREATE INDEX versions_artifact ON versions(artifact_id);
CREATE TRIGGER immutable_acceptance_requirements_delete BEFORE DELETE ON acceptance_requirements BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_acceptance_requirements_update BEFORE UPDATE ON acceptance_requirements BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_captured_outcome_simulations_delete BEFORE DELETE ON captured_outcome_simulations BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_captured_outcome_simulations_update BEFORE UPDATE ON captured_outcome_simulations BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_discrepancies_delete BEFORE DELETE ON discrepancies BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_discrepancies_update BEFORE UPDATE ON discrepancies BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_events_delete BEFORE DELETE ON events BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_events_update BEFORE UPDATE ON events BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_evidence_delete BEFORE DELETE ON evidence BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_evidence_update BEFORE UPDATE ON evidence BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_findings_delete BEFORE DELETE ON findings BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_findings_update BEFORE UPDATE ON findings BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_history_delete BEFORE DELETE ON history BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_history_update BEFORE UPDATE ON history BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_lifecycle_evidence_delete BEFORE DELETE ON lifecycle_evidence BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_lifecycle_evidence_update BEFORE UPDATE ON lifecycle_evidence BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_lineage_delete BEFORE DELETE ON lineage BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_lineage_update BEFORE UPDATE ON lineage BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_operations_delete BEFORE DELETE ON operations BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_operations_update BEFORE UPDATE ON operations BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_outcomes_delete BEFORE DELETE ON outcomes BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_outcomes_update BEFORE UPDATE ON outcomes BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_playback_results_coherence_insert BEFORE INSERT ON playback_results WHEN NOT ((NEW.result='exact_playback_succeeded' AND NEW.exact=1 AND NEW.divergence IS NULL) OR (NEW.result='diverged' AND NEW.exact=0 AND NEW.divergence IS NOT NULL)) BEGIN SELECT RAISE(ABORT,'incoherent playback result'); END;
CREATE TRIGGER immutable_playback_results_coherence_update BEFORE UPDATE ON playback_results WHEN NOT ((NEW.result='exact_playback_succeeded' AND NEW.exact=1 AND NEW.divergence IS NULL) OR (NEW.result='diverged' AND NEW.exact=0 AND NEW.divergence IS NOT NULL)) BEGIN SELECT RAISE(ABORT,'incoherent playback result'); END;
CREATE TRIGGER immutable_playback_results_delete BEFORE DELETE ON playback_results BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_playback_results_update BEFORE UPDATE ON playback_results BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_projection_rebuild_status_insert BEFORE INSERT ON projection_rebuild_status WHEN NEW.status != 'complete' AND NEW.authoritative != 0 BEGIN SELECT RAISE(ABORT,'incoherent projection authority'); END;
CREATE TRIGGER immutable_projection_rebuild_status_update BEFORE UPDATE ON projection_rebuild_status WHEN NEW.status != 'complete' AND NEW.authoritative != 0 BEGIN SELECT RAISE(ABORT,'incoherent projection authority'); END;
CREATE TRIGGER immutable_projection_rebuilds_delete BEFORE DELETE ON projection_rebuilds BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_projection_rebuilds_update BEFORE UPDATE ON projection_rebuilds BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_projections_insert BEFORE INSERT ON projections WHEN NEW.status != 'complete' AND NEW.authoritative != 0 BEGIN SELECT RAISE(ABORT,'incoherent projection authority'); END;
CREATE TRIGGER immutable_projections_update BEFORE UPDATE ON projections WHEN NEW.status != 'complete' AND NEW.authoritative != 0 BEGIN SELECT RAISE(ABORT,'incoherent projection authority'); END;
CREATE TRIGGER immutable_replay_metadata_delete BEFORE DELETE ON replay_metadata BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_replay_metadata_update BEFORE UPDATE ON replay_metadata BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_retrospectives_delete BEFORE DELETE ON retrospectives BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_retrospectives_update BEFORE UPDATE ON retrospectives BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_reviewer_findings_delete BEFORE DELETE ON reviewer_findings BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_reviewer_findings_update BEFORE UPDATE ON reviewer_findings BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_versions_delete BEFORE DELETE ON versions BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_versions_update BEFORE UPDATE ON versions BEGIN SELECT RAISE(ABORT,'immutable'); END;
